import React, { useState } from "react";
import './Whatsbot.css'; // Add your styles here, I'll show how you can use the same styles.

const WhatsBot = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState([
    { sender: "bot", text: "Hi there and thank you for contacting us. Welcome to <strong>The Lakeside Camping CHAT.</strong>" },
    { sender: "bot", text: "How can we help you today?" },
    { sender: "bot", text: "<em>Please Type Something To Continue</em><br />Book a <strong>Camping Spot</strong> 🏕️<br />" }
  ]);

  const [userMessage, setUserMessage] = useState("");

  const handleSendMessage = () => {
    if (userMessage.trim()) {
      setMessages([
        ...messages,
        { sender: "user", text: userMessage },
        { sender: "bot", text: "How can I assist you further?" } // You can replace this with dynamic bot responses
      ]);
      setUserMessage(""); // Reset input after sending
      setTimeout(() => showMenu(), 500); // Show the menu after user sends a message
    }
  };

  const showMenu = () => {
    setMessages([
      ...messages,
      {
        sender: "bot",
        text: `<button onClick="showPackages()">What are the packages?</button>
                <button onClick="showSubMenu('How to reach the location?')">How to reach the location?</button>
                <button onClick="showSubMenu('What are the available activities?')">What are the available activities?</button>
                <button onClick="showSubMenu('Are pets allowed?')">Are pets allowed?</button>
                <button onClick="showSubMenu('What are the safety measures?')">What are the safety measures?</button>`
      }
    ]);
  };

  const showPackages = () => {
    setMessages([
      ...messages,
      {
        sender: "bot",
        text: `
          <button onClick="showPackageDetails('Camp Stay')">Camp Stay</button>
          <button onClick="showPackageDetails('Glamp Stay')">Glamp Stay</button>
          <button onClick="showPackageDetails('Cottage Stay')">Cottage Stay</button>
        `
      }
    ]);
  };

  const showPackageDetails = (packageName) => {
    const details = getPackageDetails(packageName);
    setMessages([...messages, { sender: "bot", text: details }]);
  };

  const getPackageDetails = (packageName) => {
    // Use your existing package details, can be dynamic as per the logic.
    if (packageName === "Camp Stay") {
      return `
        <strong>Camp Stay: ₹900</strong>
        <ul>
          <li>Meal</li>
          <li>Tent Accommodation</li>
          <li>Sports & Activities</li>
        </ul>
      `;
    }
    // Handle other packages similarly
    return "";
  };

  const toggleChatPopup = () => {
    setIsOpen(!isOpen);
  };

  return (
    <div>
      <button onClick={toggleChatPopup}>Open Chat</button>

      {isOpen && (
        <div className="chat-container">
          <div className="chat-header">
            <img src="Pawna-Camp-Logo-SVG (1).svg" alt="Chat Icon" />
            <span>Lakeside Camping</span>
          </div>
          <div className="chat-body">
            {messages.map((message, index) => (
              <div key={index} className={`message ${message.sender}`}>
                <div dangerouslySetInnerHTML={{ __html: message.text }} />
              </div>
            ))}
          </div>
          <div className="chat-footer">
            <input
              type="text"
              value={userMessage}
              onChange={(e) => setUserMessage(e.target.value)}
              placeholder="Type a message..."
            />
            <button onClick={handleSendMessage}>Send</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default WhatsBot;
